const errors = $input.all();
if (!errors || errors.length === 0 || !errors[0].json.id) {
  return [{ json: { has_errors: false, count: 0 } }];
}
return [{ json: { has_errors: true, count: errors.length, errors: errors.map(e => e.json) } }];

// Split errors for processing
const data = $input.first().json;
return data.errors.map(e => ({ json: e }));

const aiRes = $input.first().json;
const errorData = $('Split Errors').first().json;
const content = aiRes?.choices?.[0]?.message?.content || '';
let analysis;
try {
  const clean = content.replace(/```json|```/g,'').trim();
  analysis = JSON.parse(clean.match(/\{[\s\S]*\}/)?.[0] || clean);
} catch {
  analysis = { title: 'Unknown Error', description: content, root_cause: '', fix_steps: [], category: 'General', severity: 'medium' };
}
return [{ json: { error_id: errorData.id, error_message: errorData.message, ...analysis } }];
